import{_ as d}from"./chunks/MushroomPatch__377.BJE_HXOQ.js";import{c as e,Q as o,j as s,m as a}from"./chunks/framework.BPKcPtvA.js";const M=JSON.parse('{"title":"蘑菇丛 / Mushroom Patch","description":"带任务流程的特殊事件；代码名和页面名都按 Mushroom Patch 保留，完成任务后可从自己的牌组中选择 1 张并获得复制，同时解锁 Impervious 天赋。","frontmatter":{"title":"蘑菇丛 / Mushroom Patch","description":"带任务流程的特殊事件；代码名和页面名都按 Mushroom Patch 保留，完成任务后可从自己的牌组中选择 1 张并获得复制，同时解锁 Impervious 天赋。"},"headers":[],"relativePath":"buildings/mushroom-patch.md","filePath":"buildings/mushroom-patch.md"}'),r={name:"buildings/mushroom-patch.md"};function c(h,t,n,i,m,l){return o(),s("div",null,[...t[0]||(t[0]=[a('<section class="dq-profession-hero dq-feature-hero"><div><p class="dq-kicker">Dungeon Feature · 事件</p><h1>蘑菇丛</h1><p class="dq-lede">带任务流程的特殊事件；代码名和页面名都按 Mushroom Patch 保留，完成任务后可从自己的牌组中选择 1 张并获得复制，同时解锁 Impervious 天赋。</p><p class="dq-original">原名：Mushroom Patch · 类名：MushroomPatch</p><div class="dq-tag-row"><span>事件</span><span>AddWeirdFeature 中占 15%。</span></div></div><div class="dq-profession-portrait dq-feature-portrait"><img src="'+d+'" alt="Mushroom Patch" loading="lazy"></div></section><section class="dq-wide-panel"><h2>Metadata</h2><div class="dq-meta-grid"><span title="wiki 中使用的中文名称。"><strong>中文名</strong><em>蘑菇丛</em></span><span title="游戏原始名称或代码中对应名称。"><strong>英文名</strong><em>Mushroom Patch</em></span><span title="反编译类型或创建 feature 时使用的内部名称。"><strong>类名</strong><em>MushroomPatch</em></span><span title="用于图鉴分组。"><strong>类别</strong><em>事件</em></span><span title="从地牢生成和奖励分配中恢复出的生成入口。"><strong>生成方式</strong><em>AddWeirdFeature 中占 15%。</em></span></div></section><section class="dq-section-block"><h2>机制说明</h2><div class="dq-mechanic-list"><p>MushroomPatch 有 StartQuest、SpawnMushrooms、CompleteQuestQuery、CompleteQuest 等完整任务入口：先接任务，再在地图上生成绿色 Mushroom，吃够要求数量后回来结算。</p><p>完成任务后的牌组处理不是随机奖励池，而是打开牌组选择窗口：从自己牌组中选 1 张牌，并获得一张同名复制。</p><p>Mushroom 单体效果由 MushroomEffect 决定，并使用 strength 字段作为数值；效果文本里的 X 就是该 Mushroom 的 strength。</p><p>默认绿色蘑菇随机池来自 Mushroom.ACTUAL_MUSHROOM_EFFECTS；Curse 有完整处理分支和文本，但不在默认随机池里。</p><p>成就 MUSHROOM / A Little Trip 要求完成 mushroom patch quest，奖励是解锁 Impervious 天赋。</p></div></section><section class="dq-section-block"><h2>任务流程</h2><table class="dq-data-table"><thead><tr><th>阶段</th><th>规则</th></tr></thead><tbody><tr><td>StartQuest</td><td>接受任务后在地牢中生成绿色蘑菇目标。</td></tr><tr><td>SpawnMushrooms</td><td>生成需要寻找/食用的 Mushroom 对象。</td></tr><tr><td>CompleteQuestQuery</td><td>吃够要求数量后回到 MushroomPatch 触发完成查询。</td></tr><tr><td>GetCardReward</td><td>打开牌组选择窗口，提示从自己的牌组中选择 1 张并获得复制。</td></tr><tr><td>ResolveCopy</td><td>把选中的牌复制 1 张加入牌组；这里不调用随机奖励池。</td></tr><tr><td>CompleteQuest</td><td>完成 mushroom patch quest；成就 MUSHROOM / A Little Trip 解锁 Impervious 天赋。</td></tr></tbody></table></section><section class="dq-section-block"><h2>完成奖励</h2><p class="dq-note">Mushroom Patch 完成后的牌组处理是复制玩家自己选择的牌，不是从全局奖励卡池随机抽牌。</p><table class="dq-data-table"><thead><tr><th>环节</th><th>规则</th></tr></thead><tbody><tr><td>选牌</td><td>打开自己的牌组，只从已有牌里选择 1 张。</td></tr><tr><td>获得</td><td>向牌组加入该牌的 1 张同名复制。</td></tr><tr><td>随机性</td><td>完成奖励本身不随机；随机部分在任务期间吃绿色蘑菇时结算。</td></tr></tbody></table></section><section class="dq-section-block"><h2>蘑菇效果</h2><p class="dq-note">MushroomPatch 任务会生成绿色 Mushroom。每个 Mushroom 从默认 16 个权重槽里抽一个效果，X 是该蘑菇初始化时写入的 strength。</p><table class="dq-data-table"><thead><tr><th>效果 ID</th><th>默认池</th><th>具体效果</th><th>原文提示</th></tr></thead><tbody><tr><td><code>GAIN_HEALTH</code></td><td>2/16</td><td>获得 X 点最大生命；调用 GainMaxHealth(X)。</td><td>You gain X maximum health!</td></tr><tr><td><code>LOSE_HEALTH</code></td><td>1/16</td><td>失去 X 点最大生命；调用 LoseMaxHealth(X)。</td><td>You lose X maximum health!</td></tr><tr><td><code>TELEPORT</code></td><td>2/16</td><td>传送到地图上的其他位置。</td><td>You find yourself somewhere else...</td></tr><tr><td><code>GAIN_MANA</code></td><td>2/16</td><td>获得 X 点最大法力；调用 GainMana(X)。</td><td>You gain X maximum mana!</td></tr><tr><td><code>LOSE_MANA</code></td><td>1/16</td><td>失去 X 点最大法力；调用 LoseMana(X)。</td><td>You lose X maximum mana!</td></tr><tr><td><code>CURSE</code></td><td>0/16</td><td>向牌组加入 Curse；TakeEffect 支持这个分支，但默认绿色蘑菇随机池不会抽到。</td><td>You feel dangerously sick and add a curse card to your deck</td></tr><tr><td><code>GAIN_EXP</code></td><td>2/16</td><td>获得 X 点经验。</td><td>You gain X experience!</td></tr><tr><td><code>LOSE_EXP</code></td><td>1/16</td><td>失去 X 点经验。</td><td>You lose X experience!</td></tr><tr><td><code>DAMAGE</code></td><td>2/16</td><td>受到 X 点伤害。</td><td>You take X damage!</td></tr><tr><td><code>HEAL</code></td><td>3/16</td><td>回复 X 点生命。</td><td>You heal X health!</td></tr></tbody></table></section><section class="dq-section-block"><h2>随机奖励权重</h2><table class="dq-data-table"><thead><tr><th>楼层组</th><th>概率</th><th>说明</th></tr></thead><tbody><tr><td>特殊建筑</td><td>15%</td><td>AddWeirdFeature 中随机数落在 0.70 到 0.85 区间。</td></tr></tbody></table></section><section class="dq-action-row"><a class="dq-button" href="/buildings">回到地牢建筑图鉴</a><a class="dq-button dq-button-secondary" href="/mechanics/dungeon-generation">查看地牢生成</a></section>',8)])])}const b=e(r,[["render",c]]);export{M as __pageData,b as default};
